import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart, ResponsiveChartContainer, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface Category {
  name: string;
  itemCount: number;
  estimatedCost: number;
}

interface WidgetData {
  categories: Category[];
  estimatedTotalCost: number;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const widgetData = response.data.data as WidgetData;
  const metaData = response.data.meta as MetaData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: metaData.primaryColor }}>
              Grocery Categories
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Estimated Total Cost: ${widgetData.estimatedTotalCost.toFixed(2)}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'pie',
                  data: widgetData.categories.map((category) => ({
                    id: category.name,
                    value: category.estimatedCost,
                  })),
                  color: metaData.primaryColor,
                },
              ]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <PieChart />
              </g>
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={0.5}>
            {widgetData.categories.map((category, index) => (
              <Chip
                key={index}
                label={`${category.name}: $${category.estimatedCost.toFixed(2)}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: metaData.accentColor, color: '#FFFFFF' }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
